import { expect, test as base, vi } from "vitest";
import type { getUser as GetUserFunction } from "./user";

vi.mock("next/headers", () => ({
  cookies: async () => ({
    getAll: () => [] as { name: string; value: string }[],
    set: () => {},
  }),
}));

const test = base.extend<{ getUser: typeof GetUserFunction }>({
  getUser: async ({}, provide) => {
    process.env.NEXT_PUBLIC_SUPABASE_URL ??= "http://127.0.0.1:54321";
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY ??=
      "REDACTED";
    const { getUser } = await import("./user");
    await provide(getUser);
  },
});

test("getUser: 未ログイン状態では null を返す（実 DB 疎通）", async ({ getUser }) => {
  const user = await getUser();
  expect(user).toBeNull();
});

import * as v from 'valibot'

const supabasePublicConfigSchema = v.object({
    url: v.string(),
    anonKey: v.string(),
})

type SupabasePublicConfig = v.InferOutput<typeof supabasePublicConfigSchema>

const supabasePublicConfig = v.parse(supabasePublicConfigSchema, {
    url: process.env.NEXT_PUBLIC_SUPABASE_URL,
    anonKey: process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
})

export function getSupabaseConfig(): SupabasePublicConfig {
    return { ...supabasePublicConfig }
}

